import React from 'react';
import { BrowserRouter as Router, Routes, Route, Link } from "react-router-dom";
import './App.css';

// דפי לומדה (פונקציות פשוטות לדוגמה)
function TheoryPage() { return <h2>📘 תיאוריה כללית</h2>; }
function SimulationPage() { return <h2>💣 סימולציות</h2>; }
function PracticePage() { return <h2>🧪 תרגול מעשי</h2>; }
function ToolsPage() { return <h2>🛠 כלים נוספים</h2>; }
function SummaryPage() { return <h2>📊 סיכום וסטטיסטיקות</h2>; }

export default function App() {
  return (
    <Router>
      <div className="App">
        <h1>לומדת סימולציות Ransomware – <span style={{ color: "#ff1744" }}>ByteMe 🧠</span></h1>
        <nav>
          <Link to="/theory"><button>📘 תיאוריה כללית</button></Link>
          <Link to="/simulation"><button>💣 סימולציות</button></Link>
          <Link to="/practice"><button>🧪 תרגול מעשי</button></Link>
          <Link to="/tools"><button>🛠 כלים נוספים</button></Link>
          <Link to="/summary"><button>📊 סיכום וסטטיסטיקות</button></Link>
        </nav>
        <Routes>
          <Route path="/theory" element={<TheoryPage />} />
          <Route path="/simulation" element={<SimulationPage />} />
          <Route path="/practice" element={<PracticePage />} />
          <Route path="/tools" element={<ToolsPage />} />
          <Route path="/summary" element={<SummaryPage />} />
          <Route path="/" element={<div style={{marginTop: "30px"}}>בחר עמוד</div>} />
        </Routes>
      </div>
    </Router>
  );
}
